import boto3

def create_sns_subscription():
    sns = boto3.client('sns')

    topic = input("Enter the SNS Topic ARN: ")
    while True:
        user_provided_url = input("Enter the subscription endpoint URL (or type 'exit' to finish): ")
        if user_provided_url.lower() == 'exit':
            break

        try:
            response = sns.subscribe(
                TopicArn=topic,
                Protocol='https',
                Endpoint=user_provided_url
            )
            print(f"Subscription ARN: {response['SubscriptionArn']} for endpoint: {user_provided_url}")
        except Exception as e:
            print(f"An error occurred: {e}")

if __name__ == "__main__":
    create_sns_subscription()